import anthropic
import json
from typing import Any

client = anthropic.Anthropic()

# Tool definition: every field is load-bearing.
# The model reads this schema at inference time to decide when and how to call the tool.
WEATHER_TOOL = {
    "name": "get_weather",
    "description": (
        "Return the current weather for a given city. "
        "Call this tool whenever the user asks about current weather conditions. "
        "Do not call it for historical weather or forecasts beyond 24 hours."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "city": {
                "type": "string",
                "description": "City name, e.g. 'London' or 'New York'.",
            },
            "units": {
                "type": "string",
                "enum": ["celsius", "fahrenheit"],
                "description": "Temperature unit. Default to celsius unless the user specifies otherwise.",
            },
        },
        "required": ["city"],
    },
}


def get_weather(city: str, units: str = "celsius") -> dict[str, Any]:
    """Stub implementation -- replace with real API call."""
    return {"city": city, "temperature": 18, "condition": "Partly cloudy", "units": units}


TOOL_REGISTRY: dict[str, Any] = {
    "get_weather": get_weather,
}


def run_agent(user_message: str, max_turns: int = 10) -> str:
    """Run the agent loop until the model stops calling tools or max_turns is reached."""
    messages = [{"role": "user", "content": user_message}]
    system = (
        "You are a helpful assistant. Use the get_weather tool to answer weather questions. "
        "Always report the city name and temperature in your final answer."
    )

    for turn in range(max_turns):
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            system=system,
            tools=[WEATHER_TOOL],
            messages=messages,
        )

        # Accumulate the assistant message exactly as returned.
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in response.content:
                if block.type == "text":
                    return block.text
            return ""

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    fn = TOOL_REGISTRY.get(block.name)
                    if fn is None:
                        result = {"error": f"Unknown tool: {block.name}"}
                    else:
                        try:
                            result = fn(**block.input)
                        except Exception as exc:
                            result = {"error": str(exc)}
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": json.dumps(result),
                    })
            messages.append({"role": "user", "content": tool_results})

    return "Agent reached maximum turns without completing."


if __name__ == "__main__":
    print(run_agent("What is the weather like in Tokyo right now?"))

# Bad: vague description gives the model no guidance on when to call the tool
BAD_TOOL = {
    "name": "search",
    "description": "Search for information.",
    "input_schema": {
        "type": "object",
        "properties": {"query": {"type": "string"}},
        "required": ["query"],
    },
}

# Good: the description explains what the tool does, when to use it,
# and what kind of query to pass.
GOOD_TOOL = {
    "name": "search_company_docs",
    "description": (
        "Search the company knowledge base for HR, finance, and technical policies. "
        "Use this tool when the user asks about internal company procedures or standards. "
        "Pass a concise, keyword-focused query -- do not pass the full user question verbatim."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "query": {
                "type": "string",
                "description": "Concise search query, 3-8 words.",
            }
        },
        "required": ["query"],
    },
}
